def create_executor(
    host: str = 'localhost',
    port: int = 6379,
    password: Optional[str] = None,
    key_prefix: str = 'cache:',
    preregister_safe_scripts: bool = True,
    allow_only_preregistered: bool = False,
    ssl: bool = False,
) -> SecureLuaScriptExecutor:
    """
    Factory function to create a configured SecureLuaScriptExecutor.
    """
    executor = SecureLuaScriptExecutor(
        host=host,
        port=port,
        password=password,
        key_prefix=key_prefix,
        allow_only_preregistered=allow_only_preregistered,
        ssl=ssl,
    )

    if preregister_safe_scripts:
        for name, script_info in SAFE_SCRIPTS.items():
            executor.register_script(name, script_info['script'])

    return executor


